// scripts/backfill-brand-data.cjs
// ============================================================
// 给已有的报告（generated by old template）手动补 __BRAND_DATA__ 块
// 解析渲染后的 HTML，把 8 维数据重新组装成 JSON 写入 <script id="__BRAND_DATA__">
// ============================================================

const fs = require('node:fs');
const path = require('node:path');
const cheerio = require('cheerio');

const ROOT = path.join(__dirname, '..');
const RADAR_LABELS = ['克制', '温度感', '游戏化', '科技感', '情感连接', '识别强度'];

function esc(s) {
  return String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// 从 detail-item 块里把每节内容拆出来
function extractByLabel($, html, idx) {
  // idx 0=Logo, 1=色板, 2=字体, 3=摄影, 4=调性, 5=定位, 6=用户, 7=卖点
  const labels = ['Logo', '色板', '字体系统', '摄影风格', '品牌调性', '品牌定位', '目标用户', '核心卖点'];
  const item = $(`.detail-item:has(.detail-label:contains("${labels[idx]}"))`).first();
  if (!item.length) return null;
  return item.find('.detail-value').html() || '';
}

function extractLogos(html) {
  // 简版：从 detail-value 里抓类型: xxx
  const m = html.match(/类型：<strong>([^<]+)<\/strong>/);
  return m ? m[1].trim() : '';
}

function extractTones(html) {
  // "关键词：<strong>...</strong>、<strong>...</strong>..."
  const cleaned = html.replace(/<br>/g, ' ').replace(/关键词：/, '');
  const tags = [];
  cleaned.replace(/<strong>([^<]+)<\/strong>/g, (_, t) => {
    tags.push(t.trim());
  });
  return tags;
}

function extractToneSummary(html) {
  // 调性块里 <em>...</em> 是总结；或者去掉标签后取末尾非粗体文字
  const em = html.match(/<em>([^<]+)<\/em>/);
  if (em) return em[1].trim();
  // fallback: 取 em 之前的文字
  const cleaned = html.replace(/<br>/g, '\n').replace(/关键词：/, '').replace(/<[^>]+>/g, ' ').trim();
  return cleaned;
}

function extractPositioning(html) {
  // "Tagline：<em>...</em><br>...一句话..."
  const taglineM = html.match(/Tagline：<em>([^<]+)<\/em>/);
  const tagline = taglineM ? taglineM[1].trim() : '';
  // 去掉 Tagline 部分，剩余的就是一句话定位
  let rest = html.replace(/Tagline：<em>[^<]+<\/em><br>/, '').replace(/<br>/g, ' ').replace(/<[^>]+>/g, ' ').trim();
  return { tagline, statement: rest };
}

function extractTargetUser(html) {
  const lines = html.split(/<br>/).map((s) => s.trim()).filter(Boolean);
  const get = (key) => {
    const line = lines.find((l) => l.startsWith(key + '：'));
    return line ? line.replace(key + '：', '').trim() : '';
  };
  return {
    age: get('年龄'),
    identity: get('身份'),
    pain: get('痛点'),
    scene: get('场景'),
  };
}

function extractSellingPoints(html) {
  const lines = html.split(/<br>/).map((s) => s.trim()).filter(Boolean);
  return lines
    .filter((l) => /^\d+\./.test(l))
    .map((l) => l.replace(/^\d+\.\s*/, '').trim());
}

function extractRadar(html) {
  // 从 window.__RADAR_DATA__ = { values: [...] }
  const m = html.match(/values:\s*\[([\d.,\s]+)\]/);
  if (!m) return {};
  const vals = m[1].split(',').map((v) => Number(v.trim()));
  const radar = {};
  RADAR_LABELS.forEach((label, i) => {
    radar[label] = vals[i] ?? 5;
  });
  return radar;
}

function extractPalette($) {
  const items = [];
  $('.palette .swatch').each((_, el) => {
    // 优先从 swatch-block 的 style attribute 取 hex（准确）
    const bg = $(el).find('.swatch-block').attr('style') || '';
    const styleMatch = bg.match(/background\s*:\s*(#[0-9A-Fa-f]+)/);
    const hex = styleMatch ? styleMatch[1].toUpperCase() : '';
    // name 从 .swatch-info 的 span 后面的 text node 取
    const infoEl = $(el).find('.swatch-info');
    const hexSpanText = infoEl.find('span').first().text().trim();
    // 完整 info text（去掉 <span> 里的 hex）
    const fullText = infoEl.text().trim();
    let name = fullText.replace(hexSpanText, '').trim();
    if (!name) name = '';
    if (hex) items.push({ hex, name });
  });
  return items;
}

function extractTypography(html) {
  // "标题：xxx<br>正文：xxx<br><em>xxx</em>"
  const cleaned = html.replace(/<br>/g, '\n').replace(/<[^>]+>/g, ' ').trim();
  return { note: cleaned };
}

function extractPhotography(html) {
  // 抓类型 + 描述
  const typeM = html.match(/类型：<strong>([^<]+)<\/strong>/);
  const type = typeM ? typeM[1].trim() : '';
  const cleaned = html.replace(/<br>/g, '\n').replace(/<[^>]+>/g, ' ').trim();
  return { type, description: cleaned };
}

function extractLogo(html) {
  const typeM = html.match(/类型：<strong>([^<]+)<\/strong>/);
  const cleaned = html.replace(/<br>/g, '\n').replace(/<[^>]+>/g, ' ').trim();
  return { type: typeM ? typeM[1].trim() : '', description: cleaned };
}

function extractBrandMeta($, html, fileName) {
  // 从 brand-name 取 name + category + country
  // DOM 结构: <div class="brand-name">name <span class="tag">category · country</span></div>
  const wrap = $('.brand-card .brand-name').first();
  if (!wrap.length) return { name: '', category: '', country: '' };
  const nameNode = wrap.contents().filter((_, n) => n.type === 'text').first();
  let name = nameNode ? nameNode.text().trim() : wrap.clone().children().remove().end().text().trim();
  const tag = wrap.find('.tag').first();
  const tagText = tag.text().trim();
  // 例: "Health Wearable · Finland" 或 "Sleep Tech / Family Wellness · United States"
  const parts = tagText.split(/\s+·\s+/);
  const category = (parts[0] || '').trim();
  const country = (parts[1] || '').trim();
  name = name.replace(/\s+/g, ' ').trim();
  // 如果 name 完全没有英文（LLM 只给了中文），从文件名补救
  // 例: "b-o-20260622.html" -> "B-O"
  if (!/[A-Za-z]/.test(name) && fileName) {
    const base = fileName.replace(/-\d{8}\.html$/i, '');
    // 每段首字母大写，段间用 "-" 连接
    const asciiName = base.split('-').map((p) => p.charAt(0).toUpperCase() + p.slice(1)).join('-');
    if (asciiName) name = asciiName;
  }
  return { name, category, country };
}

function extractTagline($) {
  // 找 .brand-name 之后的 tag 之前的 tagline
  const item = $('.detail-item:has(.detail-label:contains("品牌定位"))').first();
  if (!item.length) return '';
  const html = item.find('.detail-value').html() || '';
  const m = html.match(/Tagline：<em>([^<]+)<\/em>/);
  return m ? m[1].trim() : '';
}

function extractSummary($) {
  const block = $('.summary-block p').first();
  return block.text().trim();
}

function extractCreatedAt(html) {
  // "cover-meta">2026-06-22 · Brand Research ·..." (· 可能是 &middot; 实体或字符)
  let m = html.match(/(\d{4}-\d{2}-\d{2})[^<]*?Brand\s*Research/i);
  if (!m) m = html.match(/cover-meta[^>]*>\s*(\d{4}-\d{2}-\d{2})/);
  return m ? m[1] : new Date().toISOString().slice(0, 10);
}

function slugify(s) {
  return String(s || 'brand').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '') || 'brand';
}

function processFile(filePath) {
  const fileName = path.basename(filePath);
  console.log(`\n处理: ${fileName}`);
  let html = fs.readFileSync(filePath, 'utf8');

  // 已存在 __BRAND_DATA__ 则替换它（允许幂等）
  if (html.includes('id="__BRAND_DATA__"')) {
    html = html.replace(/\s*<script\s+id="__BRAND_DATA__"\s+type="application\/json">[\s\S]*?<\/script>/i, '');
  }

  const $ = cheerio.load(html);

  const { name, category, country } = extractBrandMeta($, html, fileName);
  const tagline = extractTagline($);
  const summary = extractSummary($);

  const logoHtml = extractByLabel($, html, 0) || '';
  const paletteHtml = ''; // 通过 extractPalette 拿
  const typoHtml = extractByLabel($, html, 2) || '';
  const photoHtml = extractByLabel($, html, 3) || '';
  const toneHtml = extractByLabel($, html, 4) || '';
  const posHtml = extractByLabel($, html, 5) || '';
  const tuHtml = extractByLabel($, html, 6) || '';
  const spHtml = extractByLabel($, html, 7) || '';

  const palette = extractPalette($);
  const logo = extractLogo(logoHtml);
  const typography = extractTypography(typoHtml);
  const photography = extractPhotography(photoHtml);
  const tone = extractTones(toneHtml);
  const toneSummary = extractToneSummary(toneHtml);
  const { tagline: posTagline, statement: positioning } = extractPositioning(posHtml);
  const targetUser = extractTargetUser(tuHtml);
  const sellingPoints = extractSellingPoints(spHtml);
  const radar = extractRadar(html);

  const createdAt = extractCreatedAt(html);
  const slug = slugify(name);
  const dateCompact = createdAt.replace(/-/g, '');
  const id = `${slug}-${dateCompact}`;

  const primaryColors = palette.slice(0, 4).map((p) => p.hex);

  const payload = {
    id,
    name,
    nameZh: name + ' 品牌视觉研究',
    url: '',
    tagline: posTagline || tagline,
    category,
    country,
    year: '',
    summary,
    primaryColors,
    palette,
    logo,
    typography,
    photography,
    tone,
    toneSummary,
    positioning,
    targetUser,
    sellingPoints,
    radar,
    radarValues: RADAR_LABELS.map((k) => radar[k] ?? 5),
    meta: {
      favicon: '',
      ogImage: '',
      heroImage: '',
      logoCandidates: [],
    },
    reportFile: fileName,
    reportUrl: './' + fileName,
    createdAt,
  };

  const block = `\n    <script id="__BRAND_DATA__" type="application/json">${esc(JSON.stringify(payload))}</script>\n`;
  // 插在 </head> 之前
  if (html.includes('</head>')) {
    html = html.replace('</head>', block + '  </head>');
  } else {
    console.log('  WARN: 没找到 </head>，跳过。');
    return false;
  }

  fs.writeFileSync(filePath, html, 'utf8');
  console.log(`  ✓ 写入 ${id}: ${payload.palette.length} 色 / ${tone.length} 调性 / ${sellingPoints.length} 卖点`);
  return true;
}

const files = ['oura-20260622.html', 'hatch-20260622.html', 'linear-20260622.html', 'b-o-20260622.html'];
let updated = 0;
for (const f of files) {
  const p = path.join(ROOT, f);
  if (!fs.existsSync(p)) {
    console.log(`SKIP: ${f} 不存在`);
    continue;
  }
  if (processFile(p)) updated++;
}
console.log(`\nDONE: 更新了 ${updated} 个文件`);